CREATE TABLE "rate_cards" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "client_company_id" uuid REFERENCES "crm_companies"("id") ON DELETE cascade, "show_id" uuid REFERENCES "shows"("id") ON DELETE cascade, "name" text NOT NULL, "currency" text DEFAULT 'USD' NOT NULL, "effective_from" date, "effective_to" date, "is_active" boolean DEFAULT true NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE "rate_card_items" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "organization_id" uuid NOT NULL REFERENCES "organizations"("id") ON DELETE cascade, "rate_card_id" uuid NOT NULL REFERENCES "rate_cards"("id") ON DELETE cascade, "service_rate_id" uuid REFERENCES "service_rates"("id") ON DELETE set null, "category" text NOT NULL, "unit" text NOT NULL, "rate" numeric(14,2) NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE UNIQUE INDEX "rate_card_items_card_category_unit_idx" ON "rate_card_items" ("rate_card_id", "category", "unit");
ALTER TABLE "billables" ADD COLUMN "rate_source" text;
ALTER TABLE "billables" ADD COLUMN "rate_snapshot" jsonb;
ALTER TABLE "billables" ADD COLUMN "override_reason" text;
